const d = $input.first().json;

const isMidCall = !d.call_id && (d.caller_name || d.caller_phone);

const vars = d.retell_llm_dynamic_variables || {};
const analysis = d.call_analysis || {};
const customData = analysis.custom_analysis_data || {};

const callerName = d.caller_name || vars.caller_name || '';
const callerPhone = d.caller_phone || vars.caller_phone || d.from_number || '';
const propertyAddress = d.property_address || vars.property_address || 'not provided';
const concernType = d.concern_type || vars.concern_type || 'not specified';
const description = d.concern_description || vars.concern_description || vars.description || '';
const urgencyFlag = d.urgency_flag || vars.urgency_flag || customData.urgency_level || 'routine';
const callType = vars.call_type || customData.service_type_interest || 'new_inquiry';
const afterHours = vars.after_hours === 'true' || vars.after_hours === true;
const intakeCollected = callerName.length > 0 && callerPhone.length > 0;

const startTs = parseInt(d.start_timestamp) || 0;
const endTs = parseInt(d.end_timestamp) || 0;
const durationSecs = startTs > 0 && endTs > 0 ? Math.round((endTs - startTs) / 1000) : 0;

const out = {
  call_id: d.call_id || 'mid-call-' + Date.now(),
  call_status: isMidCall ? 'in_progress' : (d.call_status || ''),
  caller_name: callerName,
  caller_phone: callerPhone,
  property_address: propertyAddress,
  concern_type: concernType,
  description: description,
  urgency_flag: urgencyFlag,
  call_type: callType,
  after_hours: afterHours,
  intake_collected: intakeCollected,
  call_summary: analysis.call_summary || description || 'Intake collected mid-call',
  user_sentiment: analysis.user_sentiment || 'Unknown',
  intake_complete: customData.intake_complete || intakeCollected,
  call_outcome: customData.call_outcome || (isMidCall ? 'intake_collected' : ''),
  transcript: (d.transcript || '').substring(0, 2000),
  call_duration_seconds: durationSecs,
  received_at: new Date().toISOString()
};
return [{ json: out }];
